#### `src/generator.ts`

This is the `Generator` interface implementation, exactly parallel to `PrismaClientTsGenerator`:

```typescript
import fs from 'node:fs/promises'
import path from 'node:path'

import Debug from '@prisma/debug'
import { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generateRestClient } from './generate-client'

const debug = Debug('prisma:generator-rest-client')

function getOutputPath(config: GeneratorConfig): string {
  if (!config.output) {
    throw new Error(
      'An output path is required for the `rest-client` generator. ' +
      'Please provide an output path in your schema file.'
    )
  }
  const { fromEnvVar, value } = config.output
  if (fromEnvVar) {
    const env = process.env[fromEnvVar]
    if (!env) throw new Error(`Environment variable "${fromEnvVar}" is not set.`)
    return env
  }
  return value as string
}

export class RestClientGenerator implements Generator {
  readonly name = 'rest-client'

  getManifest(config: GeneratorConfig): Promise<GeneratorManifest> {
    return Promise.resolve({
      prettyName: 'Prisma REST Client',
      defaultOutput: getOutputPath(config),
    })
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = getOutputPath(options.generator)
    const content = generateRestClient(options.dmmf)

    debug('writing generated client to %s', outputDir)

    await fs.mkdir(outputDir, { recursive: true })
    await fs.writeFile(path.join(outputDir, 'client.ts'), content, 'utf8')
  }
}
```

Key decisions:
- `getManifest` calls `getOutputPath(config)` and if no output is configured it throws. This matches the TS generator's pattern of requiring an explicit output path.
- No engine version or `requiresEngines` — REST client generation needs no query engine.
- `getOutputPath` inlines what `parseEnvValue` from `@prisma/internals` does, so `@prisma/internals` is not a production dependency. This is important: the requirement says dependencies are only `@prisma/dmmf`, `@prisma/generator`, `@prisma/generator-helper`, and `@prisma/debug`.
- The manifest's `defaultOutput` is read from the config at manifest time because `getManifest` is called before `generate` and is the mechanism for telling Prisma CLI where to write. If the user omits `output`, we throw early. This is the exact same pattern as the TS generator.

