import { describe, test, expect } from 'vitest'
import { mapScalarToTs, mapFieldToTs } from '../src/type-mapper'
import type * as DMMF from '@prisma/dmmf'

describe('mapScalarToTs', () => {
  test('maps String to string', () => expect(mapScalarToTs('String')).toBe('string'))
  test('maps Int to number', () => expect(mapScalarToTs('Int')).toBe('number'))
  test('maps Float to number', () => expect(mapScalarToTs('Float')).toBe('number'))
  test('maps Boolean to boolean', () => expect(mapScalarToTs('Boolean')).toBe('boolean'))
  test('maps DateTime to string', () => expect(mapScalarToTs('DateTime')).toBe('string'))
  test('maps BigInt to bigint', () => expect(mapScalarToTs('BigInt')).toBe('bigint'))
  test('maps Decimal to string', () => expect(mapScalarToTs('Decimal')).toBe('string'))
  test('maps Bytes to string', () => expect(mapScalarToTs('Bytes')).toBe('string'))
  test('maps Json to unknown', () => expect(mapScalarToTs('Json')).toBe('unknown'))
  test('passes through unknown types', () => expect(mapScalarToTs('MyEnum')).toBe('MyEnum'))
})

describe('mapFieldToTs', () => {
  function makeField(overrides: Partial<DMMF.Field>): DMMF.Field {
    return {
      kind: 'scalar', name: 'field', isRequired: true, isList: false,
      isUnique: false, isId: false, isReadOnly: false, hasDefaultValue: false,
      type: 'String',
      ...overrides,
    } as DMMF.Field
  }

  test('required scalar', () => {
    expect(mapFieldToTs(makeField({ type: 'String', isRequired: true }))).toBe('string')
  })
  test('optional scalar becomes nullable', () => {
    expect(mapFieldToTs(makeField({ type: 'String', isRequired: false }))).toBe('string | null')
  })
  test('list scalar', () => {
    expect(mapFieldToTs(makeField({ type: 'Int', isList: true, isRequired: true }))).toBe('number[]')
  })
  test('optional list', () => {
    expect(mapFieldToTs(makeField({ type: 'Int', isList: true, isRequired: false }))).toBe('number[] | null')
  })
  test('enum field passes through', () => {
    expect(mapFieldToTs(makeField({ kind: 'enum', type: 'Role', isRequired: true }))).toBe('Role')
  })
  test('relation field passes through model name', () => {
    expect(mapFieldToTs(makeField({ kind: 'object', type: 'Post', isRequired: true }))).toBe('Post')
  })
})
