import { mapFieldToTs, mapScalarToTs } from '../type-mapper'

describe('mapScalarToTs', () => {
  test.each([
    ['String', 'string'],
    ['Int', 'number'],
    ['Float', 'number'],
    ['Boolean', 'boolean'],
    ['DateTime', 'string'],
    ['BigInt', 'bigint'],
    ['Decimal', 'string'],
    ['Bytes', 'string'],
    ['Json', 'unknown'],
  ])('maps %s to %s', (prismaType, tsType) => {
    expect(mapScalarToTs(prismaType)).toBe(tsType)
  })

  test('passes through unknown types unchanged', () => {
    expect(mapScalarToTs('MyEnum')).toBe('MyEnum')
    expect(mapScalarToTs('SomeModel')).toBe('SomeModel')
  })
})

describe('mapFieldToTs', () => {
  function makeField(overrides: Partial<DMMF.Field>): DMMF.Field {
    return {
      kind: 'scalar',
      name: 'field',
      isRequired: true,
      isList: false,
      isUnique: false,
      isId: false,
      isReadOnly: false,
      hasDefaultValue: false,
      type: 'String',
      ...overrides,
    } as DMMF.Field
  }

  test('required scalar maps to base type', () => {
    expect(mapFieldToTs(makeField({ type: 'String', isRequired: true }))).toBe('string')
  })

  test('optional scalar becomes nullable union', () => {
    expect(mapFieldToTs(makeField({ type: 'String', isRequired: false }))).toBe('string | null')
  })

  test('required list scalar', () => {
    expect(mapFieldToTs(makeField({ type: 'Int', isList: true, isRequired: true }))).toBe('number[]')
  })

  test('optional list becomes nullable', () => {
    expect(mapFieldToTs(makeField({ type: 'Int', isList: true, isRequired: false }))).toBe('number[] | null')
  })

  test('enum field kind passes through the type name', () => {
    expect(mapFieldToTs(makeField({ kind: 'enum', type: 'Role', isRequired: true }))).toBe('Role')
  })

  test('object (relation) field passes through the model name', () => {
    expect(mapFieldToTs(makeField({ kind: 'object', type: 'Post', isRequired: true }))).toBe('Post')
  })

  test('optional relation becomes nullable', () => {
    expect(mapFieldToTs(makeField({ kind: 'object', type: 'Post', isRequired: false }))).toBe('Post | null')
  })
})

