import type * as DMMF from '@prisma/dmmf'
import { describe, expect, test } from 'vitest'

import { generateRestClient } from '../generate-client'

function makeField(overrides: Partial<DMMF.Field>): DMMF.Field {
  return {
    kind: 'scalar',
    name: 'id',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    type: 'Int',
    ...overrides,
  } as DMMF.Field
}

function makeDmmf(models: DMMF.Model[], enums: DMMF.DatamodelEnum[] = []): DMMF.Document {
  return {
    datamodel: {
      models,
      enums,
      types: [],
      indexes: [],
    },
    schema: {
      inputObjectTypes: { prisma: [], model: [] },
      outputObjectTypes: { prisma: [], model: [] },
      enumTypes: { prisma: [], model: [] },
      fieldRefTypes: { prisma: [] },
    },
    mappings: {
      modelOperations: [],
      otherOperations: { read: [], write: [] },
    },
  } as unknown as DMMF.Document
}

function makeModel(name: string, fields: DMMF.Field[]): DMMF.Model {
  return {
    name,
    dbName: null,
    schema: null,
    fields,
    uniqueFields: [],
    uniqueIndexes: [],
    primaryKey: null,
  } as unknown as DMMF.Model
}

const USER_MODEL = makeModel('User', [
  makeField({ name: 'id', isId: true, hasDefaultValue: true, type: 'Int' }),
  makeField({ name: 'email', type: 'String' }),
  makeField({ name: 'name', type: 'String', isRequired: false }),
  makeField({ name: 'role', kind: 'enum', type: 'Role' }),
  makeField({ name: 'posts', kind: 'object', type: 'Post', isList: true }),
])

const POST_MODEL = makeModel('Post', [
  makeField({ name: 'id', isId: true, hasDefaultValue: true, type: 'Int' }),
  makeField({ name: 'title', type: 'String' }),
  makeField({ name: 'authorId', type: 'Int' }),
  makeField({ name: 'author', kind: 'object', type: 'User', isRequired: true }),
])

const ROLE_ENUM: DMMF.DatamodelEnum = {
  name: 'Role',
  values: [{ name: 'USER', dbName: null }, { name: 'ADMIN', dbName: null }],
}

describe('generateRestClient', () => {
  test('emits file header', () => {
    const output = generateRestClient(makeDmmf([]))
    expect(output).toContain('// Generated by @prisma/generator-rest-client. Do not edit manually.')
  })

  test('emits enum type aliases', () => {
    const output = generateRestClient(makeDmmf([], [ROLE_ENUM]))
    expect(output).toContain(`export type Role = "USER" | "ADMIN"`)
  })

  test('emits model interface with scalar fields', () => {
    const output = generateRestClient(makeDmmf([USER_MODEL], [ROLE_ENUM]))
    expect(output).toContain('export interface User {')
    expect(output).toContain('id: number')
    expect(output).toContain('email: string')
    expect(output).toContain('name: string | null')
    expect(output).toContain('role: Role')
    expect(output).toContain('posts: Post[]')
  })

  test('emits model client class', () => {
    const output = generateRestClient(makeDmmf([USER_MODEL]))
    expect(output).toContain('export class UserClient {')
  })

  test('findMany method uses GET', () => {
    const output = generateRestClient(makeDmmf([USER_MODEL]))
    expect(output).toContain('async findMany(): Promise<User[]>')
    expect(output).toContain('fetch(`${this.baseUrl}/user`)')
  })

  test('findUnique method builds query params from where', () => {
    const output = generateRestClient(makeDmmf([USER_MODEL]))
    expect(output).toContain('async findUnique(where: { id: number }): Promise<User | null>')
    expect(output).toContain('fetch(`${this.baseUrl}/user?${params}`)')
  })

  test('create method excludes auto-generated id and relations from data type', () => {
    const output = generateRestClient(makeDmmf([USER_MODEL]))
    expect(output).toContain(`async create(data: Omit<User, "id" | "posts">): Promise<User>`)
  })

  test('update method wraps data in Partial', () => {
    const output = generateRestClient(makeDmmf([USER_MODEL]))
    expect(output).toContain(`async update(where: { id: number }, data: Partial<Omit<User, "id" | "posts">>): Promise<User>`)
  })

  test('delete method uses DELETE verb', () => {
    const output = generateRestClient(makeDmmf([USER_MODEL]))
    expect(output).toContain("async delete(where: { id: number }): Promise<User>")
    expect(output).toContain("method: 'DELETE'")
  })

  test('emits RestClient composing all model clients', () => {
    const output = generateRestClient(makeDmmf([USER_MODEL, POST_MODEL]))
    expect(output).toContain('export class RestClient {')
    expect(output).toContain('readonly user: UserClient')
    expect(output).toContain('readonly post: PostClient')
    expect(output).toContain('this.user = new UserClient(baseUrl)')
    expect(output).toContain('this.post = new PostClient(baseUrl)')
  })

  test('model with no auto-generated id uses full model type for create data', () => {
    const model = makeModel('Tag', [
      makeField({ name: 'slug', isId: true, hasDefaultValue: false, type: 'String' }),
      makeField({ name: 'label', type: 'String' }),
    ])
    const output = generateRestClient(makeDmmf([model]))
    expect(output).toContain('async create(data: Tag): Promise<Tag>')
  })

  test('composite primary key produces multi-field where type', () => {
    const model = makeModel('PostTag', [
      makeField({ name: 'postId', isId: true, hasDefaultValue: false, type: 'Int' }),
      makeField({ name: 'tagId', isId: true, hasDefaultValue: false, type: 'Int' }),
    ])
    const output = generateRestClient(makeDmmf([model]))
    expect(output).toContain('async findUnique(where: { postId: number, tagId: number })')
  })

  test('PascalCase model name lowercases first letter for RestClient property', () => {
    const model = makeModel('BlogPost', [
      makeField({ name: 'id', isId: true, hasDefaultValue: true, type: 'Int' }),
    ])
    const output = generateRestClient(makeDmmf([model]))
    expect(output).toContain('readonly blogPost: BlogPostClient')
  })

  test('full snapshot for a two-model schema', () => {
    const output = generateRestClient(makeDmmf([USER_MODEL, POST_MODEL], [ROLE_ENUM]))
    expect(output).toMatchSnapshot()
  })
})

