  }
}

describe('RestClientGenerator', () => {
  let tmpDir: string

  beforeEach(async () => {
    tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'rest-client-test-'))
  })

  afterEach(async () => {
    await fs.rm(tmpDir, { recursive: true, force: true })
  })

  test('getManifest returns correct prettyName and defaultOutput', async () => {
    const generator = new RestClientGenerator()
    const config: GeneratorConfig = {
      name: 'restClient',
      output: { fromEnvVar: null, value: tmpDir },
      isCustomOutput: true,
      provider: { fromEnvVar: null, value: 'rest-client' },
      config: {},
      binaryTargets: [],
      previewFeatures: [],
      sourceFilePath: '/tmp/schema.prisma',
    }

    const manifest = await generator.getManifest(config)

    expect(manifest.prettyName).toBe('Prisma REST Client')
    expect(manifest.defaultOutput).toBe(tmpDir)
  })

  test('getManifest throws when output is not configured', async () => {
    const generator = new RestClientGenerator()
    const config: GeneratorConfig = {
      name: 'restClient',
      output: null,
      isCustomOutput: false,
      provider: { fromEnvVar: null, value: 'rest-client' },
      config: {},
      binaryTargets: [],
      previewFeatures: [],
      sourceFilePath: '/tmp/schema.prisma',
    }

    await expect(generator.getManifest(config)).rejects.toThrow('An output path is required')
  })

  test('generate writes client.ts to the output directory', async () => {
    const generator = new RestClientGenerator()
    const options = makeMinimalOptions(tmpDir)

    await generator.generate(options)

    const clientPath = path.join(tmpDir, 'client.ts')
    const content = await fs.readFile(clientPath, 'utf8')

    expect(content).toContain('// Generated by @prisma/generator-rest-client. Do not edit manually.')
    expect(content).toContain('export interface User {')
    expect(content).toContain('export class UserClient {')
    expect(content).toContain('export class RestClient {')
  })

  test('generate creates the output directory if it does not exist', async () => {
    const generator = new RestClientGenerator()
    const nestedDir = path.join(tmpDir, 'nested', 'output')
    const options = makeMinimalOptions(nestedDir)

    await generator.generate(options)

    const clientPath = path.join(nestedDir, 'client.ts')
    const stat = await fs.stat(clientPath)
    expect(stat.isFile()).toBe(true)
  })

  test('generate resolves output from an environment variable', async () => {
    const generator = new RestClientGenerator()
    const envVar = 'TEST_GENERATOR_OUTPUT_' + Date.now()
    process.env[envVar] = tmpDir

    const config: GeneratorConfig = {
      name: 'restClient',
      output: { fromEnvVar: envVar, value: null },
      isCustomOutput: true,
      provider: { fromEnvVar: null, value: 'rest-client' },
      config: {},
      binaryTargets: [],
      previewFeatures: [],
      sourceFilePath: '/tmp/schema.prisma',
    }
    const options = { ...makeMinimalOptions(tmpDir), generator: config }

    try {
      await generator.generate(options)
      const clientPath = path.join(tmpDir, 'client.ts')
      await expect(fs.stat(clientPath)).resolves.toBeDefined()
    } finally {
      delete process.env[envVar]
    }
  })
})

