import type * as DMMF from '@prisma/dmmf'

import { CodeBuilder } from './code-builder'
import { mapFieldToTs, mapScalarToTs } from './type-mapper'

/**
 * Generates the full content of the `client.ts` file from a DMMF document.
 * Returns the TypeScript source as a string; callers are responsible for writing it to disk.
 */
export function generateRestClient(dmmf: DMMF.Document): string {
  const out = new CodeBuilder()
  emitFileHeader(out)
  emitEnums(out, dmmf.datamodel.enums)
  for (const model of dmmf.datamodel.models) {
    emitModelInterface(out, model)
    emitModelClient(out, model)
  }
  emitRootClient(out, dmmf.datamodel.models)
  return out.toString()
}

function emitFileHeader(out: CodeBuilder): void {
  out.line('// Generated by @prisma/generator-rest-client. Do not edit manually.')
}

function emitEnums(out: CodeBuilder, enums: DMMF.Document['datamodel']['enums']): void {
  for (const e of enums) {
    const values = e.values.map((v) => JSON.stringify(v.name)).join(' | ')
    out.blank().line(`export type ${e.name} = ${values}`)
  }
}

function emitModelInterface(out: CodeBuilder, model: DMMF.Model): void {
  out.blank().line(`export interface ${model.name} {`)
  for (const field of model.fields) {
    out.indented(1, `${field.name}: ${mapFieldToTs(field)}`)
  }
  out.line('}')
}

function emitModelClient(out: CodeBuilder, model: DMMF.Model): void {
  const urlPath = model.name.toLowerCase()
  const idFields = model.fields.filter((f) => f.isId)
  const whereType = buildWhereType(idFields)
  const omittedKeys = buildOmittedKeys(model)
  const createDataType = buildDataType(model.name, omittedKeys)
  const updateDataType = `Partial<${buildDataType(model.name, omittedKeys)}>`

  out.blank().line(`export class ${model.name}Client {`)
  out.indented(1, 'constructor(private readonly baseUrl: string) {}')

  emitFindMany(out, model.name, urlPath)
  emitFindUnique(out, model.name, urlPath, whereType)
  emitCreate(out, model.name, urlPath, createDataType)
  emitUpdate(out, model.name, urlPath, whereType, updateDataType)
  emitDelete(out, model.name, urlPath, whereType)

  out.line('}')
}

function buildWhereType(idFields: readonly DMMF.Field[]): string {
  if (idFields.length === 0) {
    return 'Record<string, unknown>'
  }
  const entries = idFields.map((f) => `${f.name}: ${mapScalarToTs(f.type)}`).join(', ')
  return `{ ${entries} }`
}

function buildOmittedKeys(model: DMMF.Model): string[] {
  const keys: string[] = []
  for (const field of model.fields) {
    if (field.isId && field.hasDefaultValue) {
      keys.push(field.name)
    } else if (field.kind === 'object') {
      keys.push(field.name)
    }
  }
  return keys
}

function buildDataType(modelName: string, omittedKeys: string[]): string {
  if (omittedKeys.length === 0) {
    return modelName
  }
  const keyUnion = omittedKeys.map((k) => JSON.stringify(k)).join(' | ')
  return `Omit<${modelName}, ${keyUnion}>`
}

function emitFindMany(out: CodeBuilder, modelName: string, urlPath: string): void {
  out.blank()
  out.indented(1, `async findMany(): Promise<${modelName}[]> {`)
  out.indented(2, `const res = await fetch(\`\${this.baseUrl}/${urlPath}\`)`)
  out.indented(2, `if (!res.ok) throw new Error(\`GET /${urlPath} failed: \${res.status}\`)`)
  out.indented(2, `return res.json() as Promise<${modelName}[]>`)
  out.indented(1, '}')
}

function emitFindUnique(out: CodeBuilder, modelName: string, urlPath: string, whereType: string): void {
  out.blank()
  out.indented(1, `async findUnique(where: ${whereType}): Promise<${modelName} | null> {`)
  out.indented(2, 'const params = new URLSearchParams(')
  out.indented(3, 'Object.entries(where).map(([k, v]) => [k, String(v)]),')
  out.indented(2, ')')
  out.indented(2, `const res = await fetch(\`\${this.baseUrl}/${urlPath}?\${params}\`)`)
  out.indented(2, `if (!res.ok) throw new Error(\`GET /${urlPath} failed: \${res.status}\`)`)
  out.indented(2, `return res.json() as Promise<${modelName} | null>`)
  out.indented(1, '}')
}

function emitCreate(out: CodeBuilder, modelName: string, urlPath: string, dataType: string): void {
  out.blank()
  out.indented(1, `async create(data: ${dataType}): Promise<${modelName}> {`)
  out.indented(2, `const res = await fetch(\`\${this.baseUrl}/${urlPath}\`, {`)
  out.indented(3, "method: 'POST',")
  out.indented(3, "headers: { 'Content-Type': 'application/json' },")
  out.indented(3, 'body: JSON.stringify(data),')
  out.indented(2, '})')
  out.indented(2, `if (!res.ok) throw new Error(\`POST /${urlPath} failed: \${res.status}\`)`)
  out.indented(2, `return res.json() as Promise<${modelName}>`)
  out.indented(1, '}')
}

function emitUpdate(
  out: CodeBuilder,
  modelName: string,
  urlPath: string,
  whereType: string,
  dataType: string,
): void {
  out.blank()
  out.indented(1, `async update(where: ${whereType}, data: ${dataType}): Promise<${modelName}> {`)
  out.indented(2, 'const params = new URLSearchParams(')
  out.indented(3, 'Object.entries(where).map(([k, v]) => [k, String(v)]),')
  out.indented(2, ')')
  out.indented(2, `const res = await fetch(\`\${this.baseUrl}/${urlPath}?\${params}\`, {`)
  out.indented(3, "method: 'PUT',")
  out.indented(3, "headers: { 'Content-Type': 'application/json' },")
  out.indented(3, 'body: JSON.stringify(data),')
  out.indented(2, '})')
  out.indented(2, `if (!res.ok) throw new Error(\`PUT /${urlPath} failed: \${res.status}\`)`)
  out.indented(2, `return res.json() as Promise<${modelName}>`)
  out.indented(1, '}')
}

function emitDelete(out: CodeBuilder, modelName: string, urlPath: string, whereType: string): void {
  out.blank()
  out.indented(1, `async delete(where: ${whereType}): Promise<${modelName}> {`)
  out.indented(2, 'const params = new URLSearchParams(')
  out.indented(3, 'Object.entries(where).map(([k, v]) => [k, String(v)]),')
  out.indented(2, ')')
  out.indented(2, `const res = await fetch(\`\${this.baseUrl}/${urlPath}?\${params}\`, {`)
  out.indented(3, "method: 'DELETE',")
  out.indented(2, '})')
  out.indented(2, `if (!res.ok) throw new Error(\`DELETE /${urlPath} failed: \${res.status}\`)`)
  out.indented(2, `return res.json() as Promise<${modelName}>`)
  out.indented(1, '}')
}

function emitRootClient(out: CodeBuilder, models: DMMF.Document['datamodel']['models']): void {
  out.blank().line('export class RestClient {')

  for (const model of models) {
    const propName = model.name.charAt(0).toLowerCase() + model.name.slice(1)
    out.indented(1, `readonly ${propName}: ${model.name}Client`)
  }

  out.blank().indented(1, 'constructor(baseUrl: string) {')
  for (const model of models) {
    const propName = model.name.charAt(0).toLowerCase() + model.name.slice(1)
    out.indented(2, `this.${propName} = new ${model.name}Client(baseUrl)`)
  }
  out.indented(1, '}')
  out.line('}')
}

import fs from 'node:fs/promises'
import path from 'node:path'

import Debug from '@prisma/debug'
import type { EnvValue, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
import type { Generator } from '@prisma/generator'

import { generateRestClient } from './generate-client'

const debug = Debug('prisma:generator-rest-client')

const missingOutputMessage =
  'An output path is required for the `rest-client` generator. ' +
  'Add `output = "../path/to/generated"` in your schema generator block.'

/**
 * Resolves the generator output directory from an `EnvValue`, supporting both
 * literal values and environment variable references (`env("VAR")`).
 *
 * Inlined from `parseEnvValue` in `@prisma/internals` to avoid pulling in that
 * package as a production dependency.
 */
function resolveEnvValue(envValue: EnvValue): string {
  if (envValue.fromEnvVar) {
    const env = process.env[envValue.fromEnvVar]
    if (env == null) {
      throw new Error(`Environment variable "${envValue.fromEnvVar}" is not set.`)
    }
    return env
  }
  return envValue.value as string
}

function resolveOutput(config: GeneratorConfig): string {
  if (!config.output) {
    throw new Error(missingOutputMessage)
  }
  return resolveEnvValue(config.output)
}

export class RestClientGenerator implements Generator {
  readonly name = 'rest-client'

  getManifest(config: GeneratorConfig): Promise<GeneratorManifest> {
    return Promise.resolve({
      prettyName: 'Prisma REST Client',
      defaultOutput: resolveOutput(config),
    })
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = resolveOutput(options.generator)
    const content = generateRestClient(options.dmmf)

    debug('writing generated client to %s', outputDir)

    await fs.mkdir(outputDir, { recursive: true })
    await fs.writeFile(path.join(outputDir, 'client.ts'), content, 'utf8')
  }
}

